import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as s,e as n}from"./app-fd10997f.js";const i={},d=n(`<p>프로젝트의 서버는 NestJS를 사용하고 있다.<br> NestJS로 구성된 서버를 실행하려면 node와 npm이 있어야 패키지를 관리하고 실행할 수 있다.<br> 하지만 기본적으로 EC2 인스턴스를 만들면 Node.js와 npm 등이 설치되어 있지 않다.</p><p>그래서 aws에서 ec2 인스턴스를 만들 때 기본 제공되는 unbuntu 이미지에 Node.js와 npm 설치하고<br> git clone으로 레포지토리까지 설정을 한 다음,<br> 초기 설정한 볼륨을 이미지(AMI)로 만들어서 자동으로 생성된 인스턴스에 초기설정이 필요없게 만들려고 한다.</p><h2 id="node-js-18버전-설치하기" tabindex="-1"><a class="header-anchor" href="#node-js-18버전-설치하기" aria-hidden="true">#</a> Node.js 18버전 설치하기</h2><p>수동으로 Node.js 18버전을 설치하려고한다.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">curl</span> <span class="token parameter variable">-s</span> https://deb.nodesource.com/setup_18.x <span class="token operator">|</span> <span class="token function">sudo</span> <span class="token function">bash</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/66a5efed-58c8-4dee-ab42-ed3b21d116b3" alt="설치 안내 메세지가 보인다." tabindex="0" loading="lazy"><figcaption>설치 안내 메세지가 보인다.</figcaption></figure><p>패키지가 다운된거 같으면 다음 명령어로 설치한다.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">apt-get</span> <span class="token function">install</span> nodejs <span class="token parameter variable">-y</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>node -v</code>로 설치된 버전을 확인할 수 있다.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>v18.19.0
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="글로벌-환경에서-패키지-설치하기" tabindex="-1"><a class="header-anchor" href="#글로벌-환경에서-패키지-설치하기" aria-hidden="true">#</a> 글로벌 환경에서 패키지 설치하기</h2><p>그 다음 글로벌 환경에서 pm2를 설치한다.<br> pm2는 이 후에 서버를 실행하고 pm2로 프로세스를 관리하는 용도로 사용한다.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">npm</span> <span class="token function">install</span> <span class="token parameter variable">-g</span> pm2
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>이런 메세지가 뜬다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/5c129845-5f7c-4597-aee2-98b46e8263f8" alt="Error: EACCES: permission denied" tabindex="0" loading="lazy"><figcaption>Error: EACCES: permission denied</figcaption></figure><p>node를 sudo 권한으로 설치하고나면 패키지 설치시 permission denied가 발생한다.<br> 해결 방법은 글로벌 패키지의 디렉터리를 변경하는 것이다.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mkdir</span> ~/.npm-global
<span class="token function">npm</span> config <span class="token builtin class-name">set</span> prefix <span class="token string">&#39;~/.npm-global&#39;</span>
<span class="token function">npm</span> get prefix <span class="token parameter variable">-g</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>이렇게 설정하고 <code>npm get prefix -g</code>를 입력하면 .npm-global 경로가 뜬다면 패키지 설치가 가능하다.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>/home/ubuntu/.npm-global
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>다시 pm2 패키지를 설치해보면 정상설치가 된것을 알 수 있다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/6fa483e7-5521-4762-bfcd-9503b160ca3b" alt="설치 성공" tabindex="0" loading="lazy"><figcaption>설치 성공</figcaption></figure><p>하지만 pm2 관련 명령어를 입력하면 명령을 찾을 수 없다고 뜬다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/1199c2cc-14f3-4889-b874-28e4a1f78d0c" alt=" 명령어 실행은 불가능하다." tabindex="0" loading="lazy"><figcaption><code>pm2 list</code> 명령어 실행은 불가능하다.</figcaption></figure><p>bash 환경변수를 설정해서 명령어를 실행시 node 패키지 폴더를 자동으로 설정하게 해야한다.</p><h2 id="npm-패키지-경로-환경변수로-설정하기" tabindex="-1"><a class="header-anchor" href="#npm-패키지-경로-환경변수로-설정하기" aria-hidden="true">#</a> npm 패키지 경로 환경변수로 설정하기</h2><p>우선 터미널에 다음 명령어를 입력해보면 명령어가 작동하는 것을 알 수 있다.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">PATH</span></span><span class="token operator">=~</span>/.npm-global/bin:<span class="token environment constant">$PATH</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/6e358b40-c7ce-4d6d-ad50-fccb6dbe9d6f" alt="환경변수를 콘솔에 입력하고 를 다시 입력하면 작동한다." tabindex="0" loading="lazy"><figcaption>환경변수를 콘솔에 입력하고 <code>pm2 list</code>를 다시 입력하면 작동한다.</figcaption></figure><p>하지만 ssh이나 콘솔에서 터미널을 종료하고 다시 접속하면 패키지 명령어는 실행할 수가 없다.<br> 접속할때마다 환경변수를 입력하면 번거롭겠지만<br> .profile이나 .bashrc를 수정하고 등록하면 접속할 때마다 환경변수를 설정할 필요가 없다.<br> 우선 ~/.profile을 열어준다.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">nano</span> ~/.profile
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>텍스트 편집기가 열어진다면 맨 아래 위에서 사용했던 환경변수를 넣고 저장한다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/1e9af0bd-9f73-40f3-bcbd-fcc181325b49" alt="맨 아래  추가" tabindex="0" loading="lazy"><figcaption>맨 아래 <code>export PATH=~/.npm-global/bin:$PATH</code> 추가</figcaption></figure><p>그다음 source 명령어로 스크립트 파일을 적용하면 다시 인스턴스에 로그인했을 때도 환경변수가 적용되어<br> 설치된 패키지 명령어를 사용할 수 있다.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">source</span> ~/.profile
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/38d1b52a-033b-4052-9091-ca15ec59c941" alt="ssh로 재접속 후 명령어를 입력하면 작동한다." tabindex="0" loading="lazy"><figcaption>ssh로 재접속 후 <code>pm2 list</code>명령어를 입력하면 작동한다.</figcaption></figure>`,35),t=[d];function c(l,o){return e(),s("div",null,t)}const b=a(i,[["render",c],["__file","node-install.html.vue"]]);export{b as default};
